function (data = NULL, seed = NULL, refresh = NULL, init = NULL, 
    save_latent_dynamics = FALSE, output_dir = getOption("cmdstanr_output_dir"), 
    output_basename = NULL, sig_figs = NULL, chains = 4, parallel_chains = getOption("mc.cores", 
        1), chain_ids = seq_len(chains), threads_per_chain = NULL, 
    opencl_ids = NULL, iter_warmup = NULL, iter_sampling = NULL, 
    save_warmup = FALSE, thin = NULL, max_treedepth = NULL, adapt_engaged = TRUE, 
    adapt_delta = NULL, step_size = NULL, metric = NULL, metric_file = NULL, 
    inv_metric = NULL, init_buffer = NULL, term_buffer = NULL, 
    window = NULL, fixed_param = FALSE, show_messages = TRUE, 
    show_exceptions = TRUE, diagnostics = c("divergences", "treedepth", 
        "ebfmi"), save_metric = NULL, save_cmdstan_config = NULL, 
    cores = NULL, num_cores = NULL, num_chains = NULL, num_warmup = NULL, 
    num_samples = NULL, validate_csv = NULL, save_extra_diagnostics = NULL, 
    max_depth = NULL, stepsize = NULL) 
{
    if (!is.null(cores)) {
        warning("'cores' is deprecated. Please use 'parallel_chains' instead.")
        parallel_chains &lt;- cores
    }
    if (!is.null(num_cores)) {
        warning("'num_cores' is deprecated. Please use 'parallel_chains' instead.")
        parallel_chains &lt;- num_cores
    }
    if (!is.null(num_chains)) {
        warning("'num_chains' is deprecated. Please use 'chains' instead.")
        chains &lt;- num_chains
    }
    if (!is.null(num_warmup)) {
        warning("'num_warmup' is deprecated. Please use 'iter_warmup' instead.")
        iter_warmup &lt;- num_warmup
    }
    if (!is.null(num_samples)) {
        warning("'num_samples' is deprecated. Please use 'iter_sampling' instead.")
        iter_sampling &lt;- num_samples
    }
    if (!is.null(max_depth)) {
        warning("'max_depth' is deprecated. Please use 'max_treedepth' instead.")
        max_treedepth &lt;- max_depth
    }
    if (!is.null(stepsize)) {
        warning("'stepsize' is deprecated. Please use 'step_size' instead.")
        step_size &lt;- stepsize
    }
    if (!is.null(save_extra_diagnostics)) {
        warning("'save_extra_diagnostics' is deprecated. Please use 'save_latent_dynamics' instead.")
        save_latent_dynamics &lt;- save_extra_diagnostics
    }
    if (!is.null(validate_csv)) {
        warning("'validate_csv' is deprecated. Please use 'diagnostics' instead.")
        if (is.logical(validate_csv)) {
            if (validate_csv) {
                diagnostics &lt;- c("divergences", "treedepth", 
                  "ebfmi")
            }
            else {
                diagnostics &lt;- NULL
            }
        }
    }
    if (cmdstan_version() &gt;= "2.27.0" && cmdstan_version() &lt; 
        "2.36.0" && !fixed_param) {
        if (self$has_stan_file() && file.exists(self$stan_file())) {
            if (!is.null(self$variables()) && length(self$variables()$parameters) == 
                0) {
                stop("Model contains no parameters. Please use 'fixed_param = TRUE'.", 
                  call. = FALSE)
            }
        }
    }
    if (fixed_param) {
        save_warmup &lt;- FALSE
    }
    procs &lt;- CmdStanMCMCProcs$new(num_procs = checkmate::assert_integerish(chains, 
        lower = 1, len = 1), parallel_procs = checkmate::assert_integerish(parallel_chains, 
        lower = 1, null.ok = TRUE), threads_per_proc = assert_valid_threads(threads_per_chain, 
        self$cpp_options(), multiple_chains = TRUE), show_stderr_messages = show_exceptions, 
        show_stdout_messages = show_messages)
    model_variables &lt;- NULL
    if (is_variables_method_supported(self)) {
        model_variables &lt;- self$variables()
    }
    sample_args &lt;- SampleArgs$new(iter_warmup = iter_warmup, 
        iter_sampling = iter_sampling, save_warmup = save_warmup, 
        thin = thin, max_treedepth = max_treedepth, adapt_engaged = adapt_engaged, 
        adapt_delta = adapt_delta, step_size = step_size, metric = metric, 
        metric_file = metric_file, inv_metric = inv_metric, init_buffer = init_buffer, 
        term_buffer = term_buffer, window = window, fixed_param = fixed_param, 
        diagnostics = diagnostics, save_metric = save_metric)
    args &lt;- CmdStanArgs$new(method_args = sample_args, stan_file = self$stan_file(), 
        stan_code = suppressWarnings(self$code()), model_methods_env = private$model_methods_env_, 
        standalone_env = self$functions, model_name = self$model_name(), 
        exe_file = self$exe_file(), proc_ids = checkmate::assert_integerish(chain_ids, 
            lower = 1, len = chains, unique = TRUE, null.ok = FALSE), 
        data_file = process_data(data, model_variables), save_latent_dynamics = save_latent_dynamics, 
        seed = seed, init = init, refresh = refresh, output_dir = output_dir, 
        output_basename = output_basename, sig_figs = sig_figs, 
        opencl_ids = assert_valid_opencl(opencl_ids, self$cpp_options()), 
        model_variables = model_variables, save_cmdstan_config = save_cmdstan_config)
    runset &lt;- CmdStanRun$new(args, procs)
    runset$run_cmdstan()
    CmdStanMCMC$new(runset)
}
